// SPEC QFLUSH QS3 — watchdog.ts
// Rôle : Auto-restart limité pour un process supervisé.
import { spawnStrict } from './process.js';
const MAX_RESTART = 5;
export function attachWatchdog(state, name, command, options) {
    let disabled = false;
    const tick = () => {
        if (disabled)
            return;
        try {
            const info = state.get(name);
            if (!info)
                return;
            if (info.state === 'error') {
                if (info.restarts >= MAX_RESTART) {
                    console.warn(`[watchdog] ${name} max restarts exceeded`);
                    disabled = true;
                    return;
                }
                console.warn(`[watchdog] ${name} restarting (attempt ${info.restarts + 1})`);
                state.update(name, { state: 'restarting', restarts: info.restarts + 1 });
                spawnStrict(state, name, command, options);
            }
        }
        catch (e) {
            console.warn('[watchdog] tick error: ' + String(e));
        }
    };
    const id = setInterval(tick, 1000);
    return () => {
        clearInterval(id);
        disabled = true;
    };
}
